  bodyCandidates.find(hasPayloadKeys) ||
  binaryRead.parsed ||
  bodyCandidates[0] ||
  raw;

const parsedFromBody = Boolean(
  parseJsonSafe(raw.body) ||
  parseJsonSafe(raw.body?.body) ||
  parseJsonSafe(raw.data) ||
  parseJsonSafe(raw.rawBody)
);

const headers = raw.headers || {};
const query = raw.query || {};

const isChatTrigger = raw.chatInput !== undefined || raw.sessionId !== undefined;

const channel = String(pick(
  body.channel,
  raw.channel,
  query.channel,
  isChatTrigger ? 'n8n_chat_trigger' : null,
  headers['x-channel'],
  'web_chat'
));

const attachmentSource = pick(
  body.attachments,
  body.files,
  body.media,
  raw.attachments,
  raw.files,
  raw.media,
  []
);

const attachments = asArray(attachmentSource).map(normalizeAttachment);

const messageText = String(pick(
  body.message_text,
  body.text,
  body.chatInput,
  body.raw_message_text,
  body.message,
  raw.message_text,
  raw.text,
  raw.chatInput,
  raw.raw_message_text,
  raw.message,
  query.message_text,
  query.text,
  ''
) ?? '');

const metadata = {
  ...(body.metadata || raw.metadata || raw.meta || {}),
  received_at: new Date().toISOString(),
  raw_payload_summary: {
    parsed_from_body: parsedFromBody,
    parsed_from_binary: Boolean(binaryRead.parsed),
    selected_body_has_payload_keys: hasPayloadKeys(body),
    binary_key: binaryRead.binary_key,
    binary_text_preview: binaryRead.binary_text_preview,
    body_type: typeof raw.body,
    raw_top_level_keys: Object.keys(raw || {}).slice(0, 50),
    body_top_level_keys: Object.keys(body || {}).slice(0, 50),
    binary_keys: Object.keys(binary || {}),
    attachment_count: attachments.length,
    trigger_shape: isChatTrigger ? 'n8n_chat_trigger' : 'webhook_or_direct'
  },
  original_channel: channel
};

return [
  {
    json: {
      workspace_id: pick(
        body.workspace_id,
        body.workspaceId,
        raw.workspace_id,
        raw.workspaceId,
        query.workspace_id,
        headers['x-workspace-id'],
        null
      ),
      user_id: pick(
        body.user_id,
        body.userId,
        raw.user_id,
        raw.userId,
        query.user_id,
        headers['x-user-id'],
        null
      ),
      project_id: pick(
        body.project_id,
        body.projectId,
        raw.project_id,
        raw.projectId,
        query.project_id,
        null
      ),
      conversation_session_id: pick(
        body.conversation_session_id,
        body.conversationSessionId,
        body.session_id,
        body.sessionId,
        raw.conversation_session_id,
        raw.sessionId,
        raw.session_id,
        query.conversation_session_id,
        null
      ),
      channel,
      message_text: messageText,
      message_type: 'empty',
      links: [],
      attachments,
      attachments_summary: {
        has_attachments: attachments.length > 0,
        attachment_count: attachments.length,
        attachment_kinds: []
      },
      input_flags: {
        has_text: messageText.trim().length > 0,
        has_images: false,
        has_audio: false,
        has_video: false,
        has_links: false,
        has_attachments: attachments.length > 0,
        is_empty: messageText.trim().length === 0 && attachments.length === 0
      },
      metadata,
      errors: []
    }
  }
];

const raw = $json || {};

const messageText =
  raw.chatInput ??
  raw.message_text ??
  raw.text ??
  raw.message ??
  '';

return {
  json: {
    ...raw,

    message_text: String(messageText || ''),
    channel: raw.channel || 'n8n_chat_test',

    workspace_id:
      raw.workspace_id ||
      raw.metadata?.workspace_id ||
      '22222222-2222-4222-8222-222222222222',

    user_id:
      raw.user_id ||
      raw.metadata?.user_id ||
      '11111111-1111-4111-8111-111111111111',

    project_id:
      raw.project_id ?? null,

    conversation_session_id:
      raw.conversation_session_id ?? null,

    attachments:
      Array.isArray(raw.attachments) ? raw.attachments : [],

    metadata: {
      ...(raw.metadata || {}),
      source: raw.metadata?.source || 'n8n_chat_trigger_manual_test',
      context_injected_for_chat_test: true
    }
  }
};
